class Solution(object):
    def areaOfMaxDiagonal(self, dimensions):
        best_diag_sq = 0
        best_area = 0
        for l, w in dimensions:
            d2 = l * l + w * w
            area = l * w
            if d2 > best_diag_sq or (d2 == best_diag_sq and area > best_area):
                best_diag_sq = d2
                best_area = area
        return best_area
